import Logo from "./Logo";

const AVATAR_IMG = "https://www.figma.com/api/mcp/asset/0571e238-4422-42dd-b48c-05bf29ff44f4";

const ICON_DASHBOARD    = "https://www.figma.com/api/mcp/asset/aa901451-33b5-4882-a935-52e388f68ea2";
const ICON_APPOINTMENTS = "https://www.figma.com/api/mcp/asset/541573eb-087b-41e7-8b6c-caa1a968d14f";
const ICON_SERVICES     = "https://www.figma.com/api/mcp/asset/ab095ee4-cc33-4280-89c8-3a258620dc81";
const ICON_LOGOUT      = "https://www.figma.com/api/mcp/asset/9b5e77f2-d02a-4ac0-a1de-5df4b0a0eb20";
const ICON_STATISTICS  = "https://www.figma.com/api/mcp/asset/cac81eb2-4916-49b2-b3cf-463673ea836d";

const s = {
  sidebar: {
    position: "fixed", top: 0, left: 0, width: 341, height: "100vh",
    background: "rgba(250,243,232,0.95)", backdropFilter: "blur(10px)",
    fontFamily: "'Libre Bodoni', serif", zIndex: 100,
    display: "flex", flexDirection: "column",
  },
  logo: { display: "flex", justifyContent: "center" },
  nav: { padding: "0 29px", marginTop: 16 },
  navItem: (active) => ({
    display: "flex", alignItems: "center", gap: 12,
    padding: "11px 24px", borderRadius: 20, cursor: "pointer",
    background: active ? "#ecdcc2" : "transparent",
    fontWeight: 700, fontSize: 20, color: "#5f4a28",
    marginBottom: 12, transition: "background 0.2s",
  }),
  icon: { width: 28, height: 28, objectFit: "contain", flexShrink: 0 },
  bottom: {
    margin: "auto 29px 0", background: "#ecdcc2", borderRadius: 30,
    padding: "12px 16px", textAlign: "center", marginBottom: 20,
  },
  logoutRow: {
    display: "flex", alignItems: "center", gap: 10,
    fontWeight: 700, fontSize: 20, color: "#5f4a28", cursor: "pointer",
  },
  divider: { height: 1, background: "#c8b89a", margin: "10px 0" },
  avatar: { width: 64, height: 64, borderRadius: "50%", objectFit: "cover", margin: "6px auto", display: "block" },
  name: { fontWeight: 700, fontSize: 16, color: "#5f4a28" },
  role: { fontSize: 13, color: "#5f4a28", opacity: 0.7 },
};

export default function Sidebar({ activePage, onNavigate }) {
  return (
    <div style={s.sidebar}>
      <div style={s.logo}>
        <Logo size={138} />
      </div>
      <nav style={s.nav}>
        <div style={s.navItem(activePage === "dashboard")} onClick={() => onNavigate("dashboard")}>
          <img src={ICON_DASHBOARD} alt="Dashboard" style={s.icon} />
          Dashboard
        </div>
        <div style={s.navItem(activePage === "appointments")} onClick={() => onNavigate("appointments")}>
          <img src={ICON_APPOINTMENTS} alt="Appointments" style={s.icon} />
          Appointments
        </div>
        <div style={s.navItem(activePage === "services")} onClick={() => onNavigate("services")}>
          <img src={ICON_SERVICES} alt="Services" style={s.icon} />
          Services
        </div>
        <div style={s.navItem(activePage === "statistics")} onClick={() => onNavigate("statistics")}>
          <span style={s.statsIcon}>📊</span>
          Statistics
        </div>
      </nav>
      <div style={s.bottom}>
        <div style={s.logoutRow}>
          <img src={ICON_LOGOUT} alt="Logout" style={s.icon} />
          Log Out
        </div>
        <div style={s.divider} />
        <img src={AVATAR_IMG} alt="Admin" style={s.avatar} />
        <div style={s.name}>Luiza Mocan</div>
        <div style={s.role}>Admin</div>
      </div>
    </div>
  );
}
